#include <algorithm>
#include <iostream>
#include <unordered_map>
#include <unordered_set>
#include <vector>
using namespace std;

bool checkGT(unordered_map<int, int>& std, unordered_map<int, int> & cnt) {
	for(auto& kv: std){
        if(cnt[kv.first] < kv.second) return false;
    }
	return true;
}

string minWindow(string s, string t) {
	int n = s.size(), m = t.size(), ret = n, r = 0;
	unordered_map<int, int> std, cnt;
	for (int i = 0; i < m; i++) {
		std[t[i]]++;
	}
    int retl = -1;
	for (int i = 0; r < n; r++) {
		cnt[s[r]]++;
		while (checkGT(std, cnt) && i < n) {
			if (r - i + 1 < ret || retl == -1) {
				ret = r - i + 1;
                retl = i;
			}
			cnt[s[i]]--;
			i++;
		}
	}
	return retl == -1 ? "" : s.substr(retl, ret);
}

int main(){

    string s = "";
    string t = "aAbBcCdDeEfFgGhHiIjJkKlLmMnNoOpPqQrRsStTuUvVwWxXyYzZ";
    cout << minWindow(s, t) << endl;

    return 0;
}